import './NextThemeProvider.scss';

import React from 'react';
import { classNames } from '../../helpers/classnames';
import type { NextThemeProviderProps } from './NextThemeProvider.types';
import { ThemeScript } from './ThemeScript';

export const NextThemeProvider: React.FC<NextThemeProviderProps> = ({
	children,
	theme = 'light',
	className = '',
	...rest
}) => {
	const themeClass = theme === 'light' ? 'ds-theme--light' : 'ds-theme--dark';

	// На сервере оборачиваем детей в контейнер с классом темы,
	// чтобы без JS по умолчанию применялась светлая тема.
	// На клиенте ThemeScript дополнительно ставит класс на body.
	return (
		<>
			<ThemeScript theme={theme} />
			<div className={classNames(themeClass, className)} {...rest}>
				{children}
			</div>
		</>
	);
};
